def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 2, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 6) / (a * b * 1.1 + 2)
                    priority += val * np.sin(ratio * b / (a + 2)) ** 2
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.15)) ** 2
            for c in range(2, 7):
                priority += np.tanh(ratio * c) * np.sin(ratio / (c + 0.5)) * 1.7
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p) / (q + 1)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            for r in range(1, 4):
                priority += np.exp(-r * ratio) * np.cos(r * ratio * i) * 0.9
        elif 2 <= ratio <= 5:
            s = 0
            for x in range(1, 16):
                s += ((ratio - 2) ** x) / (x * 2.1) * np.sin(x * ratio * 1.5)
            priority = (s * np.cos(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            for y in range(1, 5):
                priority += ((ratio - 2) ** y) / (y + 0.5) * np.sin(y * ratio * i / 2)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 20):
                s += ((2 - ratio) ** n) / (n ** 2 + 1)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item**2 / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for k in range(1, 7):
                priority += np.sin(k * ratio * i * 0.9) * ((ratio - 1) ** k) / k
        elif 0.5 <= ratio < 1:
            s = 0
            for m in range(1, 18):
                s += ((1 - ratio) ** m) / (m * 3.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 7) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 3) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.4) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 20):
                s += ((0.5 - ratio) ** l) / (l * 4) * np.sin(l * ratio * 3)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.7) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for o in range(1, 9):
                priority += ((0.5 - ratio) ** o) / (o * 7) * np.sin(item * o * 1.3)
        else:
            s = 0
            for t in range(1, 15):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.cos(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for v in range(1, 10):
                priority += ((0.2 - ratio) ** v) / (v * 8) * np.cos(item * v * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if (bin_cap + item) % 2 < 1:
            priority += np.log1p(bin_cap + item) * np.sin(i + ratio)
        else:
            priority -= np.exp(-ratio) * np.cos(i * ratio)
        priorities[i] = priority
    return priorities
